import React, { useState, useEffect, useRef } from 'react';
import { slotAPI } from '../services/api';
import io from 'socket.io-client';

const SlotManagementPage = () => {
  const [slots, setSlots] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMessage, setSuccessMessage] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    date: '',
    time: '',
    duration: 30,
    topic: '',
  });
  const socketRef = useRef(null);

  useEffect(() => {
    fetchSlots();
  }, []);

  useEffect(() => {
    socketRef.current = io('http://localhost:5000', {
      auth: {
        token: sessionStorage.getItem('token') || localStorage.getItem('token'),
      },
    });

    socketRef.current.on('slot_updated', () => {
      fetchSlots();
    });

    return () => {
      socketRef.current.off('slot_updated');
      socketRef.current.disconnect();
    };
  }, []);

  const fetchSlots = async () => {
    setLoading(true);
    setError('');
    try {
      const res = await slotAPI.getMySlots();
      setSlots(res.data.slots || []);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch slots');
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: name === 'duration' ? parseInt(value, 10) : value,
    }));
  };

  const handleCreateSlot = async (e) => {
    e.preventDefault();
    setError('');
    try {
      await slotAPI.createSlot(formData);
      setSuccessMessage('Slot created successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      setFormData({ date: '', time: '', duration: 30, topic: '' });
      setShowForm(false);
      fetchSlots();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to create slot');
    }
  };

  const handleDeleteSlot = async (slotId) => {
    if (!window.confirm('Delete this slot?')) return;

    try {
      await slotAPI.deleteSlot(slotId);
      setSuccessMessage('Slot deleted successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      fetchSlots();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to delete slot');
    }
  };

  const formatDateTime = (date, time) => {
    try {
      return `${new Date(date).toLocaleDateString()} at ${time}`;
    } catch {
      return `${date} at ${time}`;
    }
  };

  return (
    <div className="container-fluid py-4 min-vh-100">
      <div className="container">
        <div className="portal-page-header">
          <span className="portal-page-kicker">Sessions</span>
          <h1 className="portal-page-title">Slot Management</h1>
          <p className="portal-page-subtitle">
            Publish your availability, review booking status, and keep upcoming sessions organized.
          </p>
        </div>

        {error && (
          <div className="alert alert-danger alert-dismissible fade show" role="alert">
            {error}
            <button type="button" className="btn-close" onClick={() => setError('')}></button>
          </div>
        )}

        {successMessage && (
          <div className="alert alert-success alert-dismissible fade show" role="alert">
            {successMessage}
            <button
              type="button"
              className="btn-close"
              onClick={() => setSuccessMessage('')}
            ></button>
          </div>
        )}

        <div className="row g-4 mb-4">
          <div className="col-md-4">
            <div className="card portal-stat-card shadow-sm">
              <div className="card-body">
                <div className="portal-stat-label">Total Slots</div>
                <div className="portal-stat-value">{slots.length}</div>
              </div>
            </div>
          </div>
          <div className="col-md-4">
            <div className="card portal-stat-card shadow-sm">
              <div className="card-body">
                <div className="portal-stat-label">Booked</div>
                <div className="portal-stat-value">{slots.filter((slot) => slot.status === 'Booked').length}</div>
              </div>
            </div>
          </div>
          <div className="col-md-4">
            <div className="card portal-stat-card shadow-sm">
              <div className="card-body">
                <div className="portal-stat-label">Available</div>
                <div className="portal-stat-value">{slots.filter((slot) => slot.status !== 'Booked').length}</div>
              </div>
            </div>
          </div>
        </div>

        <div className="card portal-section-card shadow-sm mb-4">
          <div className="card-body d-flex justify-content-between align-items-center flex-wrap gap-3">
            <div>
              <div className="portal-stat-label">Action</div>
              <div className="fw-semibold">Create and maintain your schedule</div>
            </div>
            <button className="btn btn-primary" onClick={() => setShowForm(!showForm)}>
              {showForm ? 'Close Form' : 'Create New Slot'}
            </button>
          </div>
        </div>

        {showForm && (
          <div className="card portal-section-card shadow-sm mb-4">
            <div className="card-header bg-primary fw-bold">Create New Slot</div>
            <div className="card-body p-4">
              <form onSubmit={handleCreateSlot}>
                <div className="row">
                  <div className="col-md-6 mb-3">
                    <label htmlFor="date" className="form-label">Date</label>
                    <input type="date" className="form-control" id="date" name="date" value={formData.date} onChange={handleInputChange} required />
                  </div>
                  <div className="col-md-6 mb-3">
                    <label htmlFor="time" className="form-label">Time</label>
                    <input type="time" className="form-control" id="time" name="time" value={formData.time} onChange={handleInputChange} required />
                  </div>
                  <div className="col-md-6 mb-3">
                    <label htmlFor="duration" className="form-label">Duration (minutes)</label>
                    <input type="number" className="form-control" id="duration" name="duration" value={formData.duration} onChange={handleInputChange} min="15" max="120" step="15" />
                  </div>
                  <div className="col-md-6 mb-3">
                    <label htmlFor="topic" className="form-label">Topic</label>
                    <input type="text" className="form-control" id="topic" name="topic" value={formData.topic} onChange={handleInputChange} placeholder="Optional session topic" />
                  </div>
                </div>
                <button type="submit" className="btn btn-primary w-100">Create Slot</button>
              </form>
            </div>
          </div>
        )}

        {loading ? (
          <div className="text-center py-5">
            <div className="spinner-border text-primary" role="status">
              <span className="visually-hidden">Loading...</span>
            </div>
          </div>
        ) : slots.length === 0 ? (
          <div className="card portal-section-card shadow-sm">
            <div className="portal-empty-state">No slots created yet.</div>
          </div>
        ) : (
          <div className="card portal-section-card shadow-sm">
            <div className="card-header bg-primary fw-bold">Your Slots</div>
            <div className="table-responsive">
              <table className="table table-hover mb-0">
                <thead className="table-light">
                  <tr>
                    <th>Date & Time</th>
                    <th>Duration</th>
                    <th>Topic</th>
                    <th>Status</th>
                    <th>Student</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {slots.map((slot) => (
                    <tr key={slot._id}>
                      <td className="fw-bold">{formatDateTime(slot.date, slot.time)}</td>
                      <td>{slot.duration} min</td>
                      <td>{slot.topic || 'Not specified'}</td>
                      <td>
                        <span className={`badge ${slot.status === 'Booked' ? 'bg-success' : 'bg-primary'}`}>
                          {slot.status}
                        </span>
                      </td>
                      <td>{slot.studentId?.name || 'Unassigned'}</td>
                      <td>
                        <button className="btn btn-sm btn-danger" onClick={() => handleDeleteSlot(slot._id)}>
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default SlotManagementPage;
